1	/**
2	 * CM6 adapter for outline mode's decorations. All the pure computation
3	 * (depth/supplementalDepth, per-line guide depths) lives in decorate.ts;
4	 * this module only turns those facts into CM6 decorations/DOM, gated
5	 * per-editor on outline mode via the public `editorInfoField` — same
6	 * gating pattern as keymap.ts's grammarExtension.
7	 *
8	 * Two mechanisms, because Obsidian renders atom kinds two different ways in
9	 * Live Preview:
10	 *
11	 * - Most lines (headings, paragraphs, list items, code fences, plain
12	 *   blockquotes) render as a real `.cm-line` that CM6 lets us decorate
13	 *   declaratively: one class plus one CSS custom property per fact (never
14	 *   an inline shorthand property), so styles.css owns the actual
15	 *   `padding-left`/`margin-left` rules and their units (additive-only
16	 *   indentation, Experiment 1) plus the guide-line gradient (Experiment 2b,
17	 *   see the "Guide lines" section below).
18	 * - Tables, callouts, raw HTML blocks, and horizontal rules are rendered as
19	 *   opaque replacement widgets (`.cm-embed-block`, or `.hr` for the rule) —
20	 *   confirmed live: a `Decoration.line` targeting that line's position has
21	 *   no effect at all (not even a class-merge partial win), because the
22	 *   widget's own `toDOM()` produces the line's DOM wholesale and neither
23	 *   CM6 nor Obsidian threads our decoration's class/attributes through it.
24	 *   These need a direct, imperative DOM patch instead — a `ViewPlugin`
25	 *   that, after each render, sets `margin-left` inline (with `!important`,
26	 *   which always wins for an inline style regardless of what any
27	 *   stylesheet rule does) on whichever such widgets are currently mounted.
28	 *
29	 * `MarginCompensation` (below) additionally patches margin-left on BOTH
30	 * mechanisms to account for Obsidian's own "readable line width" feature,
31	 * which applies a `margin-inline: auto`-centering rule to every `.cm-line`
32	 * (any div child of `.cm-content`, in fact) — a *uniform* native base
33	 * margin our own `calc(depth * unit) !important` rule was silently
34	 * *replacing* instead of adding to, confirmed live (a depth-0 heading and
35	 * a depth-1 list item under it rendered with the list-item's own box to
36	 * the LEFT of the heading's, an inverted/negative-looking indentation —
37	 * reported by real-vault testing under a community theme with a narrower
38	 * reading column than the bundled themes, where the effect became large
39	 * enough to notice; the bug itself is present under any theme/viewport
40	 * where that base margin is nonzero, bundled themes included). See its
41	 * own doc comment below for the fix.
42	 */
43	
44	import { RangeSetBuilder, StateField, type Extension, type EditorState } from '@codemirror/state';
45	import {
46	  Decoration,
47	  EditorView,
48	  ViewPlugin,
49	  type DecorationSet,
50	  type PluginValue,
51	} from '@codemirror/view';
52	import { editorInfoField } from 'obsidian';
53	import { parse } from '../parse';
54	import {
55	  computeLineGuides,
56	  decorate,
57	  type LineDecorationFact,
58	  type LineGuideFact,
59	} from './decorate';
60	import type { ModeSource } from './keymap';
61	
62	// ---- Guide lines (Experiment 2b: CSS stacked-gradient) ---------------------
63	//
64	// @replit/codemirror-indentation-markers' technique: one `--to-guides`
65	// custom property per line, a comma-joined list of repeating-linear-
66	// gradient layers (one per active ancestor depth), consumed by a single
67	// `::before` — O(1) DOM nodes regardless of depth, no JS pixel measurement,
68	// no overlay layer (contrast Experiment 2a's measured overlay divs).
69	//
70	// `to-decor-atom`/`to-decor-list` lines use `margin-left` (Experiment 1's
71	// fix for the "padding never moves the box" bug), which DOES shift the
72	// line's own box — an earlier version of this code concluded from that
73	// alone that a guide could never render on those lines, since their own
74	// `::before` (position: absolute, relative to the line's own box) can't
75	// reach a shallower ancestor's column. That reasoning had a real bug: it
76	// assumed a background is clipped to the *positioned element's own box*,
77	// but the pseudo-element's own box does NOT have to match its containing
78	// block's dimensions — `left`/`right` can widen it arbitrarily, including
79	// leftward past where the line's box starts. Confirmed live (screenshot +
80	// computed style) that nothing in the ancestor chain up to `.cm-scroller`
81	// clips that overflow (`.cm-content`/`.cm-contentContainer`/`.cm-sizer`
82	// are all `overflow: visible`; `.cm-scroller` is `overflow: auto` but its
83	// own box starts well to the left of any guide column we'd ever need).
84	//
85	// The needed compensation ("how far has this line's own box been shifted
86	// right of the global column origin") is fully known at decoration-build
87	// time for both kinds, with NO live measurement: an atom's own shift is
88	// exactly `depth * unit` (our own margin-left value). A list item's own
89	// shift is exactly `supplementalDepth * unit` (our own margin-left value)
90	// too — confirmed live that Obsidian's native hang (`text-indent`/
91	// `padding-left`, applied to the very same `.cm-line`) contributes NOTHING
92	// to the box's own position: `getBoundingClientRect()` on a list line
93	// showed its box's left edge exactly matching its `margin-left`, despite a
94	// nonzero native `padding-left`/`text-indent` also being present — because
95	// neither property moves a box's own edges (padding shifts content only;
96	// text-indent shifts only the first inline line's content, per the CSS
97	// spec), only `margin` does. So both kinds can widen their own pseudo's
98	// box by exactly `--to-own-shift` units to reach any shallower ancestor's
99	// column, with no measurement beyond the JS constants this module already
100	// computes.
101	function guideLayer(depth: number): string {
102	  const unit = 'var(--to-decor-unit, 1.5rem)';
103	  return (
104	    `repeating-linear-gradient(to right, var(--text-faint) 0 1px, transparent 1px ${unit}) ` +
105	    `calc(${depth} * ${unit}) 0 / ${unit} 100% no-repeat`
106	  );
107	}
108	
109	function guideBackground(guideDepths: readonly number[]): string {
110	  return guideDepths.map(guideLayer).join(', ');
111	}
112	
113	function lineDecoration(fact: LineDecorationFact, guide: LineGuideFact): Decoration {
114	  const styles: string[] = [];
115	  let cls: string;
116	  // Units of `--to-decor-unit` this line's own box has been shifted right
117	  // by its own margin-left — the exact compensation the guide's pseudo
118	  // needs to widen its box by, leftward, to reach a shallower ancestor's
119	  // column (see the doc comment above).
120	  let ownShiftUnits: number;
121	
122	  if (fact.isListItem) {
123	    cls = 'to-decor-list';
124	    styles.push(`--to-supp-depth: ${fact.supplementalDepth}`);
125	    ownShiftUnits = fact.supplementalDepth;
126	  } else if (fact.isAtom) {
127	    cls = 'to-decor-atom';
128	    styles.push(`--to-depth: ${fact.depth}`);
129	    ownShiftUnits = fact.depth;
130	  } else {
131	    cls = 'to-decor-block';
132	    styles.push(`--to-depth: ${fact.depth}`);
133	    ownShiftUnits = 0; // padding-left never shifts a block line's own box
134	  }
135	
136	  if (guide.guideDepths.length > 0) {
137	    cls += ' to-decor-guides';
138	    styles.push(`--to-guides: ${guideBackground(guide.guideDepths)}`);
139	    if (ownShiftUnits > 0) {
140	      styles.push(`--to-own-shift: calc(${ownShiftUnits} * var(--to-decor-unit, 1.5rem))`);
141	    }
142	  }
143	
144	  return Decoration.line({ class: cls, attributes: { style: styles.join('; ') } });
145	}
146	
147	// A blank trailingGap line carrying a guide (see computeLineGuides's doc
148	// comment) has no decorate() fact at all — no depth, no kind, nothing to
149	// indent — so it gets a minimal decoration with just the guide class/style,
150	// not the full lineDecoration() treatment.
151	function gapLineDecoration(guide: LineGuideFact): Decoration {
152	  return Decoration.line({
153	    class: 'to-decor-guides',
154	    attributes: { style: `--to-guides: ${guideBackground(guide.guideDepths)}` },
155	  });
156	}
157	
158	function computeDecorations(state: EditorState, modes: ModeSource): DecorationSet {
159	  const path = state.field(editorInfoField, false)?.file?.path;
160	  if (!path || !modes.isOutline(path)) return Decoration.none;
161	
162	  const doc = parse(state.doc.toString());
163	  // computeLineGuides is a strict superset of decorate() by line coverage
164	  // (every line decorate() covers, plus gap-only lines) — iterate it as
165	  // the primary sequence (still ascending by lineNumber, required by
166	  // RangeSetBuilder) and look up the matching decorate() fact by line
167	  // number instead of assuming index alignment, since gap lines have no
168	  // corresponding entry there at all.
169	  const factsByLine = new Map(decorate(doc).map((f) => [f.lineNumber, f]));
170	  const guides = computeLineGuides(doc);
171	  const totalLines = state.doc.lines;
172	  const builder = new RangeSetBuilder<Decoration>();
173	  for (const guide of guides) {
174	    if (guide.lineNumber >= totalLines) continue; // stale fact past a shrunk doc
175	    const from = state.doc.line(guide.lineNumber + 1).from; // CM6 lines are 1-indexed
176	    if (guide.isGapLine) {
177	      if (guide.guideDepths.length === 0) continue; // nothing to draw
178	      builder.add(from, from, gapLineDecoration(guide));
179	      continue;
180	    }
181	    const fact = factsByLine.get(guide.lineNumber);
182	    if (!fact) continue; // decorate()/computeLineGuides walks are in sync; defensive only
183	    builder.add(from, from, lineDecoration(fact, guide));
184	  }
185	  return builder.finish();
186	}
187	
188	// Obsidian's own selectors for widget-replaced atom kinds — matches tables,
189	// callouts, and raw HTML blocks (`.cm-embed-block`) plus horizontal rules
190	// (`.hr`, which oddly also carries `cm-line` but is widget-rendered all the
191	// same). Broad by design: elements it catches that don't correspond to an
192	// atom fact (e.g. an inline image embed inside a paragraph) just get their
193	// margin cleared, a no-op.
194	const WIDGET_ATOM_SELECTOR = '.cm-embed-block, .cm-line.hr';
195	
196	// Plain `.cm-line`s that carry one of our own margin-based decorations
197	// (atoms, list items) — needs the SAME native-base compensation as
198	// widgets, for the same reason (see MarginCompensation's doc comment).
199	const PLAIN_MARGIN_SELECTOR = '.cm-line.to-decor-atom, .cm-line.to-decor-list';
200	
201	class MarginCompensation implements PluginValue {
202	  constructor(
203	    private readonly view: EditorView,
204	    private readonly modes: ModeSource,
205	  ) {
206	    this.apply();
207	  }
208	
209	  docViewUpdate(): void {
210	    this.apply();
211	  }
212	
213	  destroy(): void {
214	    this.clearAll();
215	  }
216	
217	  /**
218	   * The margin-left every undecorated `.cm-line` gets natively (Obsidian's
219	   * "readable line width" centering, `margin-inline: auto` under a
220	   * `max-width` — see the module doc comment). Read live, not hardcoded or
221	   * replicated via a calc() formula, since its value depends on the
222	   * current theme/viewport/setting and isn't exposed as a plain-length CSS
223	   * custom property we could reference (`--content-margin`'s own
224	   * *specified* value is literally the keyword `auto`, not a length).
225	   * `.to-decor-block` lines never have their own margin-left touched (they
226	   * use padding), so any one of them is an uncontaminated reference; a
227	   * completely undecorated line (blank gap, preamble) works just as well.
228	   * Falls back to 0 only if the current viewport has neither (e.g. a
229	   * document that is 100% margin-decorated content with nothing else
230	   * rendered) — a graceful degradation, not silently wrong in the common
231	   * case.
232	   */
233	  private nativeMarginBasePx(): number {
234	    // `.hr` is excluded too: it carries `.cm-line` but is widget-rendered
235	    // (see WIDGET_ATOM_SELECTOR) and patched by the loop below — if a
236	    // previous `apply()` call already set its margin-left, querying it
237	    // here would read back our OWN prior value, not the native one.
238	    const ref = this.view.contentDOM.querySelector<HTMLElement>(
239	      `.cm-line:not(.to-decor-atom):not(.to-decor-list):not(.hr)`,
240	    );
241	    return ref ? parseFloat(getComputedStyle(ref).marginLeft) || 0 : 0;
242	  }
243	
244	  private apply(): void {
245	    const path = this.view.state.field(editorInfoField, false)?.file?.path;
246	    if (!path || !this.modes.isOutline(path)) {
247	      this.clearAll();
248	      return;
249	    }
250	
251	    const doc = parse(this.view.state.doc.toString());
252	    const factsByLine = new Map(decorate(doc).map((f) => [f.lineNumber, f]));
253	    const guidesByLine = new Map(computeLineGuides(doc).map((g) => [g.lineNumber, g]));
254	    const nativeBasePx = this.nativeMarginBasePx();
255	
256	    const widgets = Array.from(
257	      this.view.contentDOM.querySelectorAll<HTMLElement>(WIDGET_ATOM_SELECTOR),
258	    );
259	    for (const el of widgets) {
260	      const lineNumber = this.view.state.doc.lineAt(this.view.posAtDOM(el)).number - 1;
261	      const fact = factsByLine.get(lineNumber);
262	      if (fact?.isAtom) {
263	        // Some widgets (tables, for their row/column drag-handles) carry
264	        // their own native left padding that our margin doesn't know
265	        // about — padding never moves a box's own edge, so it just pushes
266	        // the widget's *visible content* (e.g. the <table> grid) further
267	        // right than a same-depth code block or callout, whose background
268	        // fills their own padding invisibly. Reading it live (not a
269	        // hardcoded constant) keeps this correct across themes; clamped at
270	        // 0 so a depth-0 atom never goes negative.
271	        const nativePaddingLeft = parseFloat(getComputedStyle(el).paddingLeft) || 0;
272	        // The widget's own box's rightward shift *from our own
273	        // contribution alone* — this (NOT including nativeBasePx) is also
274	        // the exact compensation a guide's pseudo-element needs to widen
