1	/**
2	 * Outline-decorations Experiment 2b (guide lines via CSS stacked-gradient)
3	 * — see docs/research/07-decoration-experiments-plan.md. Head-to-head
4	 * alternative to Experiment 2a (pixel-measured overlay), NOT a fallback:
5	 * screenshots every fixture in the shared corpus, in both bundled themes
6	 * (ground rule #2), plus targeted computed-style assertions — reading the
7	 * `::after` pseudo-element's *resolved* background, not just the raw
8	 * `--to-guides` custom property we set, so a silent cascade override
9	 * couldn't slip past unnoticed the way DOM-attribute-only checks did in
10	 * the original postmortem.
11	 *
12	 * Guides render on every kind (block, atom, list item, and — after
13	 * overriding Obsidian's native `contain: paint` — widget-replaced atoms,
14	 * table included via a second, `.table-wrapper`-decoupling fix, see
15	 * styles.css's doc comment). See styles.css's doc comments for the full
16	 * reasoning — an earlier version of this code wrongly concluded margin-
17	 * shifted lines could never render a guide at all; that was a real bug in
18	 * the reasoning, corrected after empirical pushback, not a structural CSS
19	 * limitation. Three further real bugs were found the same way (user
20	 * pushback → live verification, not assumption): the guide's own
21	 * `::before` was clobbering a blockquote's native colored bar (also
22	 * `::before`) — fixed by moving to `::after`; margin-based lines were
23	 * replacing, not adding to, Obsidian's own native "readable line width"
24	 * centering margin — fixed by `MarginCompensation` reading that native
25	 * base live and combining it; and the table's guide-vs-scroll conflict
26	 * (see styles.css) — fixed, confirmed both by computed style and by a
27	 * human actually using the table's scrollbar in a real running vault.
28	 */
29	
30	import * as fsp from 'node:fs/promises';
31	import * as path from 'node:path';
32	import { browser, expect } from '@wdio/globals';
33	import { obsidianPage } from 'wdio-obsidian-service';
34	import * as h from '../helpers.js';
35	import { ALL_DECORATION_FIXTURES } from '../fixtures/decorations.js';
36	
37	const SCREENSHOT_DIR = path.join(process.cwd(), '.obsidian-cache', 'guides-gradient-screenshots');
38	
39	async function ensureOutlineMode(notePath: string): Promise<void> {
40	  if (!(await h.isOutlineMode(notePath))) {
41	    await h.toggleOutlineMode();
42	    await h.waitForNotice('Outline mode on');
43	    await h.dismissNotices();
44	  }
45	}
46	
47	/** Number of `repeating-linear-gradient(` layers in a resolved background-image. */
48	function gradientLayerCount(backgroundImage: string): number {
49	  if (backgroundImage === 'none' || backgroundImage === '') return 0;
50	  return (backgroundImage.match(/repeating-linear-gradient\(/g) ?? []).length;
51	}
52	
53	describe('outline decorations: experiment 2b (guide lines, CSS stacked-gradient)', function () {
54	  before(async function () {
55	    await obsidianPage.resetVault();
56	    await h.resetPluginState();
57	    await fsp.mkdir(SCREENSHOT_DIR, { recursive: true });
58	  });
59	
60	  after(async function () {
61	    await h.setTheme(false);
62	  });
63	
64	  afterEach(async function () {
65	    await h.dismissNotices();
66	  });
67	
68	  it('screenshots every fixture with outline mode on, light and dark', async function () {
69	    for (const fixture of ALL_DECORATION_FIXTURES) {
70	      await h.createNote(fixture.note, fixture.md);
71	      await ensureOutlineMode(fixture.note);
72	      await browser.pause(150);
73	
74	      await h.setTheme(false);
75	      await browser.pause(150);
76	      await h.screenshotFull(SCREENSHOT_DIR, `${fixture.label}-light`);
77	
78	      await h.setTheme(true);
79	      await browser.pause(150);
80	      await h.screenshotFull(SCREENSHOT_DIR, `${fixture.label}-dark`);
81	    }
82	  });
83	
84	  it('screenshots real (non-synthetic) vault notes with outline mode on', async function () {
85	    const REAL_NOTES = [
86	      'Journal/2026-07-12.md', // tab-indented nested lists, multi-line items, a wikilink
87	      'Notes/Edge Case Zoo.md', // headings, atoms (code/table/callout), ordered list
88	      'Journal/2026-07-10.md', // a callout (widget-replaced atom) mixed with headings/lists
89	      'README.md', // a large table (widget-replaced atom)
90	    ];
91	    for (const note of REAL_NOTES) {
92	      await h.openNote(note);
93	      await ensureOutlineMode(note);
94	      await browser.pause(150);
95	
96	      const slug = note.replace(/[\/ ]/g, '-').replace(/\.md$/, '');
97	      await h.setTheme(false);
98	      await browser.pause(150);
99	      await h.screenshotFull(SCREENSHOT_DIR, `real-${slug}-light`);
100	      await h.setTheme(true);
101	      await browser.pause(150);
102	      await h.screenshotFull(SCREENSHOT_DIR, `real-${slug}-dark`);
103	
104	      await h.toggleOutlineMode(); // leave mode off for other specs
105	      await h.waitForNotice('Outline mode off');
106	      await h.dismissNotices();
107	    }
108	  });
109	
110	  it('draws no guides with outline mode off', async function () {
111	    const fixture = ALL_DECORATION_FIXTURES.find((f) => f.label === 'heading-then-list')!;
112	    await h.createNote(fixture.note, fixture.md);
113	    if (await h.isOutlineMode(fixture.note)) {
114	      await h.toggleOutlineMode();
115	      await h.waitForNotice('Outline mode off');
116	      await h.dismissNotices();
117	    }
118	    expect(await h.getLineClassList(0)).not.toContain('to-decor-guides');
119	  });
120	
121	  it('a non-list ancestor’s guide sets a resolved gradient background on its own descendant BLOCK lines', async function () {
122	    const note = 'Scratch/decorations-guide-heading-para.md';
123	    const md = ['# Parent', '', 'A child paragraph.', ''].join('\n');
124	    await h.createNote(note, md);
125	    await ensureOutlineMode(note);
126	    await browser.pause(150);
127	
128	    // "# Parent" (line 0) is the owner, not its own descendant — no guide
129	    // class on its own line.
130	    expect(await h.getLineClassList(0)).not.toContain('to-decor-guides');
