1	/**
2	 * Shared helpers for e2e specs. Everything that talks to Obsidian goes
3	 * through executeObsidian (runs inside the app); disk assertions read the
4	 * sandboxed vault copy from the test process with node:fs.
5	 */
6	
7	import { browser } from '@wdio/globals';
8	import { obsidianPage } from 'wdio-obsidian-service';
9	import { Key } from 'webdriverio';
10	import * as fsp from 'node:fs/promises';
11	import * as path from 'node:path';
12	
13	export const PLUGIN_ID = 'true-outliner';
14	
15	// ---- Notes and editor buffer -------------------------------------------
16	
17	export async function openNote(notePath: string): Promise<void> {
18	  await obsidianPage.openFile(notePath);
19	}
20	
21	/** Create (or overwrite) a note and open it. */
22	export async function createNote(notePath: string, content: string): Promise<void> {
23	  await browser.executeObsidian(
24	    async ({ app }, p, c) => {
25	      const existing = app.vault.getAbstractFileByPath(p);
26	      if (existing) await app.vault.delete(existing);
27	      const dir = p.split('/').slice(0, -1).join('/');
28	      if (dir && !app.vault.getAbstractFileByPath(dir)) await app.vault.createFolder(dir);
29	      await app.vault.create(p, c);
30	    },
31	    notePath,
32	    content,
33	  );
34	  await openNote(notePath);
35	}
36	
37	export function getBuffer(): Promise<string> {
38	  return browser.executeObsidian(({ app, obsidian }) => {
39	    const view = app.workspace.getActiveViewOfType(obsidian.MarkdownView);
40	    if (!view) throw new Error('no active markdown view');
41	    return view.editor.getValue();
42	  });
43	}
44	
45	/** Replace the whole buffer — for arranging exact test states quickly. */
46	export function setBuffer(text: string): Promise<void> {
47	  return browser.executeObsidian(({ app, obsidian }, text) => {
48	    const view = app.workspace.getActiveViewOfType(obsidian.MarkdownView);
49	    if (!view) throw new Error('no active markdown view');
50	    view.editor.setValue(text);
51	  }, text);
52	}
53	
54	/** Focus the editor and place the cursor — call before sending keys. */
55	export function setCursor(line: number, ch: number): Promise<void> {
56	  return browser.executeObsidian(
57	    ({ app, obsidian }, line, ch) => {
58	      const view = app.workspace.getActiveViewOfType(obsidian.MarkdownView);
59	      if (!view) throw new Error('no active markdown view');
60	      view.editor.focus();
61	      view.editor.setCursor({ line, ch });
62	    },
63	    line,
64	    ch,
65	  );
66	}
67	
68	/** Focus the editor and set a multi-line selection (anchor → head). */
69	export function setSelection(
70	  anchor: { line: number; ch: number },
71	  head: { line: number; ch: number },
72	): Promise<void> {
73	  return browser.executeObsidian(
74	    ({ app, obsidian }, anchor, head) => {
75	      const view = app.workspace.getActiveViewOfType(obsidian.MarkdownView);
76	      if (!view) throw new Error('no active markdown view');
77	      view.editor.focus();
78	      view.editor.setSelection(anchor, head);
79	    },
80	    anchor,
81	    head,
82	  );
83	}
84	
85	export function getCursor(): Promise<{ line: number; ch: number }> {
86	  return browser.executeObsidian(({ app, obsidian }) => {
87	    const view = app.workspace.getActiveViewOfType(obsidian.MarkdownView);
88	    if (!view) throw new Error('no active markdown view');
89	    const cursor = view.editor.getCursor();
90	    return { line: cursor.line, ch: cursor.ch };
91	  });
92	}
93	
94	/**
95	 * Force-save the active view. Obsidian autosave is debounced (~2s); every
96	 * disk assertion must sit behind this boundary or it races.
97	 */
98	export async function saveActiveFile(): Promise<void> {
99	  await browser.executeObsidian(async ({ app, obsidian }) => {
100	    const view = app.workspace.getActiveViewOfType(obsidian.MarkdownView);
101	    if (view) await view.save();
102	  });
103	}
104	
105	// ---- Disk (sandboxed vault copy) ---------------------------------------
106	
107	export function vaultFilePath(rel: string): string {
108	  return path.join(obsidianPage.getVaultPath(), rel);
109	}
110	
111	export function readVaultFile(rel: string): Promise<string> {
112	  return fsp.readFile(vaultFilePath(rel), 'utf-8');
113	}
114	
115	export async function statMtimeMs(rel: string): Promise<number> {
116	  return (await fsp.stat(vaultFilePath(rel))).mtimeMs;
117	}
118	
119	interface PluginData {
120	  outlinePaths: string[];
121	  debugCrossCheck: boolean;
122	  coexistenceWarned: boolean;
123	}
124	
125	/** Read the plugin's data.json from the sandboxed vault (null if absent). */
126	export async function readPluginData(): Promise<PluginData | null> {
127	  const configDir = await browser.executeObsidian(({ app }) => app.vault.configDir);
128	  try {
