async function retry(func, opts = {}) {
  const { retries = 4, backoff = 1e3, retryIf = () => true } = opts;
  let attempt = 0;
  let error;
  while (attempt <= retries) {
    try {
      return await func(attempt);
    } catch (e) {
      error = e;
    }
    const delay = backoff * Math.random() + backoff * Math.pow(2, attempt);
    if (!retryIf(error) || attempt >= retries) {
      throw error;
    }
    await sleep(delay);
    attempt += 1;
  }
  throw error;
}

// src/pageobjects/obsidianPage.ts
var ObsidianPage = class extends BasePage {
  getObsidianCapabilities() {
    return this.browser.requestedCapabilities[OBSIDIAN_CAPABILITY_KEY];
  }
  /**
   * Returns the path to the vault opened in Obsidian.
   * 
   * wdio-obsidian-service copies your vault before running tests, so this is the path to the temporary copy.
   */
  getVaultPath() {
    const obsidianOptions = this.getObsidianCapabilities();
    if (obsidianOptions.openVault === void 0) {
      throw Error("No vault open, set vault in wdio.conf.mts or use reloadObsidian to open a vault dynamically.");
    }
    return obsidianOptions.androidVault ?? obsidianOptions.openVault;
  }
  /** 
   * Run an Obsidian CLI command.
   * 
   * The Obsidian CLI Only works on Obsidian >=1.12.0 with installer >=1.11.7
   * See https://help.obsidian.md/cli
   */
  async runObsidianCli(args) {
    const { appVersion, installerVersion } = this.getObsidianCapabilities();
    if (semver.lt(appVersion, "1.12.0") || semver.lt(installerVersion, "1.11.7")) {
      throw Error(`Obsidian CLI only works on app >=1.12.0 and installer >=1.11.7`);
    }
    if (isAppium(this.browser.requestedCapabilities)) {
      throw Error(`Obsidian CLI only works on desktop`);
    }
    const stdout = await this.browser.execute((args2) => window.handleCli(args2), args);
    return { stdout, stderr: "" };
  }
  /**
   * Return the Obsidian config dir (just ".obsidian" unless you changed the config dir name in settings).
   */
  async getConfigDir() {
    return await this.browser.executeObsidian(({ app }) => app.vault.configDir);
  }
  /**
   * Returns the Obsidian Platform object. Useful for skipping tests based on whether you are running in desktop or
   * mobile, or based on OS.
   */
