/*
 * Outline mode decorations — additive-only indentation (Experiment 1, see
 * docs/research/07-decoration-experiments-plan.md and the postmortem it
 * links). `rem`, not `em`: custom properties resolve at the point of use,
 * so an `em`-based unit would inflate under a heading's larger font-size —
 * exactly the bug that shipped last time.
----
/*
 * `--to-marker-gutter` (Experiment 5a, see
 * docs/research/07-decoration-experiments-plan.md): a fixed, additive
 * reservation for a per-kind block marker icon, on top of the existing
 * depth-based indentation. Applies to every non-list-item line (block and
 * atom alike) — list items reserve nothing, since they keep their fully
----
/*
 * Guide lines (Experiment 2b) — CSS stacked-gradient technique
 * (@replit/codemirror-indentation-markers), see
 * docs/research/07-decoration-experiments-plan.md. decorations.ts merges a
 * `--to-guides` custom property (a comma-joined list of repeating-linear-
 * gradient layers, one per active ancestor depth) into the same line that
----
    // Depth 0 alone would be 0px (Experiment 1's own invariant) — but this
    // branch is built on top of Experiment 5a's block markers, which
    // additively reserve a fixed marker gutter on every non-list-item line,
    // even at depth 0 (the marker is the whole point of the reservation).
    // See docs/research/07-decoration-experiments-plan.md, Experiment 5a.
    expect(headingPadding).toBe('20px'); // depth 0 + --to-marker-gutter default (1.25rem)

    const topRect = await h.getLineRect(2);
----
    // hold simultaneously; a human has also confirmed live, in a real
    // running vault, that the scrollbar itself (trackpad swipe,
    // click-drag) still works with no visual or usability defects — see
    // docs/research/07-decoration-experiments-plan.md.
    const fixture = ALL_DECORATION_FIXTURES.find((f) => f.label === 'widget-atoms')!;
    await h.createNote(fixture.note, fixture.md);
    await ensureOutlineMode(fixture.note);

